+  const progress: DeliveryProgress = {
+    hasReplied: false,
+    hasDelivered: false,
+  };
+  const chunkText = buildChunkTextResolver({
+    textLimit: params.textLimit,
+    chunkMode: params.chunkMode ?? "length",
